solutions.javascript:
// Solution
function parseMediaQueries(mediaQueries) {
  let parsedQueries = [];
  for (let query of mediaQueries) {
    let features = query.split(',');
    let priority = features.length;
    parsedQueries.push({ query, priority });
  }
  return parsedQueries.sort((a, b) => b.priority - a.priority);
}

solutions.python:
class Solution:
  def parseMediaQueries(self, media_queries):
    parsed_queries = []
    for query in media_queries:
      features = query.split(',')
      priority = features.count(',') + 1
      parsed_queries.append({ 'query': query, 'priority': priority })
    return sorted(parsed_queries, key=lambda x: x['priority'], reverse=True)
